- (NSString *)iconKeyForViewType:(BOOL)isSVIPView featureBit:(NSString *)featureBit {
    WBSettingManager *manager = [WBSettingManager sharedManager];

    if (manager.IsSVIP) {
        if (!(manager.Benefit & [featureBit unsignedIntegerValue])) {
            return isSVIPView ? @"icon_v1" : @"icon_v0";
        } else {
            return isSVIPView ? @"icon_v1_svip" : @"icon_v0_svip";
        }
    }

    if (manager.IsVIP) {
        if (!(manager.Benefit & [featureBit unsignedIntegerValue])) {
            return isSVIPView ? @"icon_v1" : @"icon_v0";
        } else {
            return isSVIPView ? @"icon_v1_vip" : @"icon_v0_vip";
        }
    }

    // 处理试享权益逻辑
    if (manager.IsNew && manager.BenefitTrialProperties.count > 0) {
        for (NSDictionary *dict in manager.BenefitTrialProperties) {
            NSInteger currentBenefitBit = [dict[@"benefitBit"] integerValue];
            if (currentBenefitBit == [featureBit integerValue]) {
                id trialTimesObject = dict[@"trialTimes"];
                if (trialTimesObject && trialTimesObject != [NSNull null]) {
                    NSInteger times = [manager trialUsageTimesForBenefitBit:[featureBit integerValue]];
                    if (times <= 0) {
                        return isSVIPView ? @"icon_v1" : @"icon_v0";
                    } else {
                        return isSVIPView ? @"icon_v1_svip" : @"icon_v0_svip";
                    }
                } else {
                    return isSVIPView ? @"icon_v1_svip" : @"icon_v0_svip";
                }
            }
        }
        return isSVIPView ? @"icon_v1" : @"icon_v0";
    }

    // 默认返回普通图标
    return isSVIPView ? @"icon_v1" : @"icon_v0";
}


