@implementation WBMineFunctionItem

- (instancetype)initWithCode:(NSString *)code icon:(NSString *)icon title:(NSString *)title {
    self = [super init];
    if (self) {
        _code = code;
        _icon = icon;
        _title = title;
        _showNotice = NO;
        _tipString = @"";
    }
    return self;
}

